      margin-top: 20px;
      padding: 0;
    }

    .pricing-card li {
      margin-bottom: 10px;
      color: #555;
    }

    .pricing-card .btn {
      margin-top: 20px;
      background: #007BFF;
      color: white;
    }

    .pricing-card .btn:hover {
      background: #0056b3;
    }

    footer {
      background: #007BFF;
      color: white;
      text-align: center;
      padding: 30px 20px;
    }

    @media (max-width: 600px) {
      header h1 {
        font-size: 2rem;
      }

